INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-57112235-moex-00137', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄對受刑人進行懲罰應予慎重。有關監獄依法或其他法律進行懲罰前應踐行之正當程序，下列敘述 何者錯誤？', '["進行懲罰前應給予受刑人陳述意見之機會，並告知其違規之原因事實及科處之懲罰", "受刑人違規情節輕微或顯堪憫恕者，得免懲罰之執行或緩予執行", "受刑人罹患疾病或有其他特別事由者，得停止執行", "監獄為調查受刑人違規事項，得對相關受刑人施以必要之區隔，期間不得逾三十日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00138', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '根據監獄行刑法第93條，受刑人因監獄行刑有下列情形之一者，得以書面或言詞向監獄提起申訴？', '["不服監獄所為影響整體受刑人權益之處分或管理措施", "因監獄對其依本法請求之事件，忽略其請求或於三個月內不依其請求作成決定，認為其權利或法律 上利益受損害", "因監獄行刑之公法上原因發生之財產給付爭議", "認為監獄處分逾越達成監獄行刑目的所為必要之範圍，而不法侵害其憲法所保障之基本權利顯非屬輕 微者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00139', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人對於廢止假釋以及不予許可假釋之處分，如有不服，得於收受處分書之翌日起幾天內向法務部 提起復審？', '["十日", "十五日", "二十日", "二十五日"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00140', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法第124條，受刑人向法務部提起復審時，應填具復審書，由復審人簽名或捺印，下列何 者非應載明之事項？', '["復審人之姓名。有委任代理人或輔佐人者，其姓名，住居所", "復審人之罪名、刑期", "復審事實及理由", "復審年、月、日"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00141', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依行刑累進處遇條例相關規定，受刑人之累進處遇事項，下列敘述何者錯誤？', '["累進處遇分四級，自第四級依次漸進", "受刑人由他監移入者，應照原級編列", "累進處遇依受刑人之刑期分成20個類別", "各級受刑人之責任分數，以其所得成績分數抵銷之，抵銷淨盡者，令其進級"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00142', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關縮短刑期與假釋之相異點，下列敘述何者錯誤？', '["假釋有執行一定刑期之限制；縮短刑期則無執行一定刑期之限制", "假釋適用有期徒刑及無期徒刑受刑人；縮短刑期則適用於有期徒刑受刑人", "假釋僅適用於累進處遇二級以上之受刑人；縮短刑期則適用於三級以上受刑人", "假釋受刑人釋放後應交付保護管束；因縮短刑期提前出獄之受刑人無交付保護管束之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00143', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法第139條規定受刑人釋放後之保護扶助事項，應由監獄調查分類科負責調查與覆查，於受 刑人釋放後委由更生保護會及其各地分會負責辦理。根據更生保護法第11條規定，實施更生保護， 得依更生人情狀，分別採用以下那三種方式進行。', '["直接保護、間接保護、暫時保護", "直接保護、間接保護、安置輔導", "直接保護、間接保護、轉銜保護", "直接保護、間接保護、保護管束"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00144', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關外役監受刑人戒護管理，依外役監條例之規定，下列敘述何者錯誤？', '["受刑人外役作業每十人以上、二十人以下為一組，由典獄長擇優指定一人為組長", "受刑人外役作業時，不得施用聯鎖", "作業成績優良者，得許於例假日或紀念日與眷同住", "受刑人以分類群居為原則。但典獄長認為必要時，得令獨居"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 47, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00145', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關監獄行刑法對於受刑人之釋放與保護相關規定，下列敘述何者正確？', '["核准假釋者，應於保護管束命令送交監獄後十二小時內釋放之", "釋放時，應斟酌被釋放者之健康，並按時令使其準備相當之衣類及出獄旅費", "受赦免者，應於公文到達後至遲四十八小時內釋放之", "受刑人依刑法第91條之1規定，經鑑定、評估，認有再犯之危險，而有施以強制治療之必要者， 監獄應於刑期屆滿前二月，將受刑人應接受強制治療之鑑定、評估報告等相關資料，送請該管檢察 署檢察官"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00146', 'judicial-57112235', 'judicial-57112235-moex-114-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關受刑人於執行中死亡，依監獄行刑法之規定，下列敘述何者錯誤？', '["監獄應即通知家屬或最近親屬，並逕報檢察署指派檢察官相驗", "家屬或最近親屬有數人者，得僅通知其中一人", "監獄應檢附相關資料，陳報監督機關", "死亡者之屍體，經依規定相驗並通知後三日內無人請領或無法通知者，得火化之，並存放於骨灰存放 設施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:49+00:00", "source_pdf_sha1": "eb79723e3a75", "answer_pdf_sha1": "e4b9650e68ac", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "205", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL)
